def generate_carpet(k):
    size = 3 ** k
    carpet = [['.' for _ in range(size)] for _ in range(size)]

    def build_carpet(k, x, y, size):
        if k == 0:
            carpet[y][x] = '#'
            return
        sub_size = size // 3
        for i in range(3):
            for j in range(3):
                if i == 1 and j == 1:
                    continue  # central block is white
                build_carpet(k - 1, x + j * sub_size, y + i * sub_size, sub_size)

    build_carpet(k, 0, 0, size)
    return carpet

def main():
    import sys
    N = int(sys.stdin.readline())
    carpet = generate_carpet(N)
    for row in carpet:
        print(''.join(row))

if __name__ == "__main__":
    main()
